class Dog(val name: String, val breed: String)
val d = Dog("Rex", "Labrador")
println(d.name)

class Circle(val radius: Double) {
    init {
        println("Circle with radius $radius created")
    }
}
val c = Circle(5.0)

class Counter {
    var count = 0
    fun increment() { count++ }
    fun value() = count
}
val c = Counter()
c.increment()
c.increment()
println(c.value())

class Box(val size: Int) {
    fun describe(): String {
        return "Box of size ${this.size}"
    }
}
println(Box(10).describe())

class Message(val text: String) {
    constructor(code: Int) : this("Code: $code")
}
println(Message(42).text)

class Circle(val radius: Double) {
    val diameter: Double
        get() = radius * 2
}
val c = Circle(5.0)
println(c.diameter)

class BankAccount(initialBalance: Double) {
    private var balance = initialBalance
    fun deposit(amount: Double) { balance += amount }
    fun getBalance() = balance
}
val acc = BankAccount(100.0)
acc.deposit(50.0)
println(acc.getBalance())

open class Animal(val name: String) {
    open fun sound() = "..."
}
class Dog(name: String) : Animal(name) {
    override fun sound() = "Woof"
}
println(Dog("Rex").sound())

class Lamp(var on: Boolean = false) {
    fun toggle() { on = !on }
}
val lamp1 = Lamp()
val lamp2 = Lamp()
lamp1.toggle()
println(lamp1.on)
println(lamp2.on)
